<span class="line"><span style="color:#CBA6F7;">    case</span><span style="color:#CDD6F4;"> provider</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">EventComplete</span><span style="color:#9399B2;">:</span></span>
