<span class="line"><span style="color:#CDD6F4;">        assistantMsg</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">AddFinish</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">event</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">Response</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">FinishReason</span><span style="color:#9399B2;">)</span></span>
